399: // Namespace returns the resolved target namespace key string.
400: // If the underlying key is the empty string, the default namespace ("default")
401: // is returned instead.
402: func (n NamespaceRequest) Namespace() string {
403: 	if n.key == "" {
404: 		return flipt.DefaultNamespace
405: 	}
406: 
407: 	return n.key
408: }
