437: // IDRequest is used to identify any sub-resources which have a unique random identifier.
438: // This is used for sub-resources with no key identifiers (e.g. rules and rollouts).
439: type IDRequest struct {
440: 	ReferenceRequest
441: 	ID string
442: }
443: 
444: // NewID constructs and configures a new *IDRequest with the provided ID string.
445: // Optionally, the target storage revision reference can also be supplied.
446: func NewID(id string, opts ...containers.Option[ReferenceRequest]) IDRequest {
447: 	p := IDRequest{ID: id}
448: 	containers.ApplyAll(&p.ReferenceRequest, opts...)
449: 	return p
