		storage.ListWithQueryParamOptions[storage.ResourceRequest](
			storage.WithPageToken("Zm9v"),
		),
	)).Return(
		storage.ResultSet[*flipt.Rollout]{
			Results: []*flipt.Rollout{
				{
					FlagKey: "flagKey",
				},
			},
			NextPageToken: "YmFy",
