						Value:           true,
					},
				},
			},
		},
		{
			name: "segments",
			req: &flipt.CreateRolloutRequest{
				FlagKey: "flagKey",
				Rank:    1,
				Rule: &flipt.CreateRolloutRequest_Segment{
